### Load data


::: {.cell}

```{.r .cell-code}
library(cbbplotR)
# manually make data using wikipedia 
# this is very time consuming, but did not find an easy way to scrape the data
# example: https://en.wikipedia.org/wiki/2000_NCAA_Division_I_baseball_tournament#Men's_College_World_Series
cws_one_seeds <- tibble::tribble(
  ~year,~team,~reg,~super,~cws,~champ_game,~champions,
  1999,"Miami FL","check","check","check","check","check",
  2000,"South Carolina","check","check","circle-xmark","circle-xmark","circle-xmark",
  2001,"Cal St. Fullerton","check","check","check","circle-xmark","circle-xmark",
  2002,"Florida St.","check","check","circle-xmark","circle-xmark","circle-xmark",
  2003,"Florida St.","check","check","circle-xmark","circle-xmark","circle-xmark",
  2004,"Texas","check","check","check","check","circle-xmark",
  2005,"Tulane","check","check","check","circle-xmark","circle-xmark",
  2006,"Clemson","check","check","check","circle-xmark","circle-xmark",
  2007,"Vanderbilt","check","circle-xmark","circle-xmark","circle-xmark","circle-xmark",
  2008,"Miami FL","check","check","check","circle-xmark","circle-xmark",
  2009,"Texas","check","check","check","check","circle-xmark",
  2010,"Arizona St.","check","check","check","circle-xmark","circle-xmark",
  2011,"Virginia","check","check","check","circle-xmark","circle-xmark",
  2012,"Florida","check","check","check","circle-xmark","circle-xmark",
  2013,"North Carolina","check","check","check","circle-xmark","circle-xmark",
  2014,"Oregon St.","check","circle-xmark","circle-xmark","circle-xmark","circle-xmark",
  2015,"UCLA","check","circle-xmark","circle-xmark","circle-xmark","circle-xmark",
  2016,"Florida","check","check","check","circle-xmark","circle-xmark",
  2017,"Oregon St.","check","check","check","circle-xmark","circle-xmark",
  2018,"Florida","check","check","check","circle-xmark","circle-xmark",
  2019,"UCLA","check","check","circle-xmark","circle-xmark","circle-xmark",
  2020,"Duke","circle-xmark","circle-xmark","circle-xmark","circle-xmark","circle-xmark", # COVID placeholder
  2021,"Arkansas","check","check","circle-xmark","circle-xmark","circle-xmark",
  2022,"Tennessee","check","check","circle-xmark","circle-xmark","circle-xmark",
  2023,"Wake Forest","check","check","check","circle-xmark","circle-xmark",
  2024,"Tennessee","check","check","check","check","question",
) 


# add in a trophy for miami 
# split the data, so we can show it side by side instead of using
# two_column_layout 
cws_one_seeds |> 
  dplyr::mutate(champions = dplyr::if_else(champions == "check", "trophy", "circle-xmark")) |> 
  dplyr::slice(1:13) -> cws_first


cws_one_seeds |> 
  dplyr::slice(14:26) -> cws_second

# combine the data
cws_full <- dplyr::bind_cols(cws_first, cws_second)
```
:::


### Make the GT table with logo and icons


::: {.cell}

```{.r .cell-code}
cws_title <- cbbplotR::gt_cbb_logo_title(title = 'Number One Overall Seed in the NCAA College Baseball Tournament Since 1999',
                                          subtitle = "Shows the NCAA Tournament performance of every college baseball number one overall seed since 1999.<br> 
                                         The number one overall seed last won the tournament in 1999 and last played for the title in 2009.",
                                          logo_link = "https://www.ncaa.com/_flysystem/public-s3/2023-07/MCWS%20No%20Date%20Logo.png",
                                          logo_height = 75)

cws_full |> 
  cbbplotR::gt_cbb_teams(team...2, team...2) |> 
  cbbplotR::gt_cbb_teams(team...9, team...9) |> 
  dplyr::mutate(team...9 = # fix the logo to be for COVID
                  dplyr::if_else(year...8 == 2020, 
                                 "<img src='https://a2.espncdn.com/combiner/i?img=%2Fi%2Fespn%2Fmisc_logos%2F500%2Fncaa.png' style='height: 25px; width: auto; vertical-align: -30%;'> COVID",
                                 team...9)) |>  
  gt::gt() |> 
  gt::fmt_markdown(columns = c(team...2, team...9)) |> 
  gt::cols_label(
    year...1 = "Year",
    team...2 = "1 Seed",
    reg...3 = "Regionals",
    super...4 = "Supers",
    cws...5 = "Participant",
    champ_game...6 = "Runner-Up",
