  gtExtras::gt_highlight_rows(rows = c(9), fill = "#FFEBEA", 
                              columns = c(year...8,
                                          team...9,
                                          reg...10, 
                                          super...11,
                                          cws...12,
                                          champ_game...13,
                                          champions...14)) |> 
  gtExtras::gt_highlight_rows(rows = c(1), fill = "#B2D8B2", 
                              columns = c(year...1,
                                          team...2,
                                          reg...3, 
                                          super...4,
